"""
Parameterized generator for GH1123_airflow_63848.

Source PR:    https://github.com/apache/airflow/pull/63848
Source Issue: N/A

Seed varies: renames 'asset' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH1123_airflow_63848'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH1123_airflow_63848'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('asset', 'asset' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH1123_airflow_63848',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'apache/airflow',
                "pr_number": 63848,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/apache/airflow/pull/63848",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'airflow-core/src/airflow/assets/manager.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nfrom collections.abc import Collection, Iterable\nfrom contextlib import contextmanager\nfrom typing import TYPE_CHECKING\n\nimport structlog\nfrom sqlalchemy import exc, or_, select\nfrom sqlalchemy.orm import joinedload\n\nfrom airflow._shared.observability.metrics.stats import Stats\nfrom airflow.configuration import conf\nfrom airflow.listeners.listener import get_listener_manager\nfrom airflow.listeners.types import AssetEvent as ListenerAssetEvent\nfrom airflow.models.asset import (\n    AssetAliasModel,\n    AssetDagRunQueue,\n    AssetEvent,\n    AssetModel,\n    AssetPartitionDagRun,\n    DagScheduleAssetAliasReference,\n    DagScheduleAssetNameReference,\n    DagScheduleAssetReference,\n    DagScheduleAssetUriReference,\n    PartitionedAssetKeyLog,\n)\nfrom airflow.models.log import Log\nfrom airflow.utils.helpers import is_container\nfrom airflow.utils.log.logging_mixin import LoggingMixin\nfrom airflow.utils.sqlalchemy import get_dialect_name, with_row_locks\n\nif TYPE_CHECKING:\n    from sqlalchemy.orm.session import Session\n\n    from airflow.models.dag import DagModel\n    from airflow.models.serialized_dag import SerializedDagModel\n    from airflow.models.taskinstance import TaskInstance\n    from airflow.serialization.definitions.assets import (\n        SerializedAsset,\n        SerializedAssetAlias,\n        SerializedAssetUniqueKey,\n    )\n    from airflow.timetables.simple import PartitionedAssetTimetable\n\nlog = structlog.get_logger(__name__)\n\n\n@contextmanager\ndef _lock_asset_model(\n    *,\n    session: Session,\n    asset_id: int,\n    max_retries: int = 10,\n    retry_delay: float = 0.1,\n):\n    """\n    Context manager to acquire a lock for AssetPartitionDagRun creation.\n\n    - SQLite: Use a no-op ORM update to trigger a write-transaction and acquire SQLite\'s global writer lock.\n    - Postgres/MySQL: uses row-level lock on AssetModel.\n    """\n    if get_dialect_name(session) == "sqlite":\n        import time\n\n        from sqlalchemy import update\n\n        # no-op update\n        # This is used to acquire SQLite\'s global writer lock.\n        stmt = update(AssetModel).where(AssetModel.id == asset_id).values(id=AssetModel.id)\n        for _ in range(max_retries):\n            try:\n                session.execute(stmt)\n                session.flush()\n            except exc.OperationalError as err:\n                err_msg = str(err).lower()\n                if "locked" in err_msg or "busy" in err_msg:\n                    session.rollback()\n                    time.sleep(retry_delay)\n                    continue\n\n            # lock acquired\n            yield\n            return\n\n        raise RuntimeError(f"Could not acquire SQLite AssetModel writer lock for asset_id={asset_id}")\n    else:\n        # Postgres/MySQL row-level lock\n        if (\n            session.scalar(\n                with_row_locks(\n                    query=select(AssetModel.id).where(AssetModel.id == asset_id),\n                    session=session,\n                    key_share=True,\n                )\n            )\n        ) is None:\n            raise RuntimeError(f"Asset {asset_id} does not exist – cannot lock.")\n\n        yield\n\n\nclass AssetManager(LoggingMixin):\n    """\n    A pluggable class that manages operations for assets.\n\n    The intent is to have one place to handle all Asset-related operations, so different\n    Airflow deployments can use plugins that broadcast Asset events to each other.\n    """\n\n    @classmethod\n    def create_assets(cls, assets: list[SerializedAsset], *, session: Session) -> list[AssetModel]:\n        """Create new assets."""\n\n        def _add_one(asset: SerializedAsset) -> AssetModel:\n            model = AssetModel.from_serialized(asset)\n            session.add(model)\n            cls.notify_asset_created(asset=asset)\n            return model\n\n        return [_add_one(a) for a in assets]\n\n    @classmethod\n    def create_asset_aliases(\n        cls,\n        asset_aliases: list[SerializedAssetAlias],\n        *,\n        session: Session,\n    ) -> list[AssetAliasModel]:\n        """Create new asset aliases."""\n\n        def _add_one(asset_alias: SerializedAssetAlias) -> AssetAliasModel:\n            model = AssetAliasModel.from_serialized(asset_alias)\n            session.add(model)\n            cls.notify_asset_alias_created(asset_assets=asset_alias)\n            return model\n\n        return [_add_one(a) for a in asset_aliases]\n\n    @classmethod\n    def _add_asset_alias_association(\n        cls,\n        alias_names: Collection[str],\n        asset_model: AssetModel,\n        *,\n        session: Session,\n    ) -> None:\n        already_related = {m.name for m in asset_model.aliases}\n        existing_aliases = {\n            m.name: m\n            for m in session.scalars(select(AssetAliasModel).where(AssetAliasModel.name.in_(alias_names)))\n        }\n        asset_model.aliases.extend(\n            existing_aliases.get(name, AssetAliasModel(name=name))\n            for name in alias_names\n            if name not in already_related\n        )\n\n    @classmethod\n    def register_asset_change(\n        cls,\n        *,\n        task_instance: TaskInstance | None = None,\n        asset: SerializedAsset | AssetModel | SerializedAssetUniqueKey,\n        extra=None,\n        source_alias_names: Collection[str] = (),\n        session: Session,\n        partition_key: str | None = None,\n        **kwargs,\n    ) -> AssetEvent | None:\n        """\n        Register asset related changes.\n\n        For local assets, look them up, record the asset event, queue dagruns, and broadcast\n        the asset event\n        """\n        from airflow.models.dag import DagModel\n\n        asset_model: AssetModel | None = session.scalar(\n            select(AssetModel)\n            .where(AssetModel.name == asset.name, AssetModel.uri == asset.uri)\n            .options(\n                joinedload(AssetModel.active),\n                joinedload(AssetModel.aliases),\n                joinedload(AssetModel.scheduled_dags).joinedload(DagScheduleAssetReference.dag),\n            )\n        )\n        if not asset_model:\n            cls.logger().warning("AssetModel %s not found; cannot create asset event.", asset)\n            return None\n\n        if not asset_model.active:\n            cls.logger().warning("Emitting event for inactive AssetModel %s", asset)\n\n        cls._add_asset_alias_association(\n            alias_names=source_alias_names, asset_model=asset_model, session=session\n        )\n\n        event_kwargs = {\n            "asset_id": asset_model.id,\n            "extra": extra or {},\n            "partition_key": partition_key,\n        }\n        if task_instance:\n            event_kwargs.update(\n                source_task_id=task_instance.task_id,\n                source_dag_id=task_instance.dag_id,\n                source_run_id=task_instance.run_id,\n                source_map_index=task_instance.map_index,\n            )\n\n        asset_event = AssetEvent(**event_kwargs)\n        session.add(asset_event)\n        session.flush()  # Ensure the event is written earlier than ADRQ entries below.\n\n        dags_to_queue_from_asset = {ref.dag for ref in asset_model.scheduled_dags if not ref.dag.is_paused}\n\n        dags_to_queue_from_asset_alias = set()\n        if source_alias_names:\n            asset_alias_models: Iterable[AssetAliasModel] = session.scalars(\n                select(AssetAliasModel)\n                .where(AssetAliasModel.name.in_(source_alias_names))\n                .options(\n                    joinedload(AssetAliasModel.scheduled_dags).joinedload(DagScheduleAssetAliasReference.dag)\n                )\n            ).unique()\n\n            for asset_alias_model in asset_alias_models:\n                asset_alias_model.asset_events.append(asset_event)\n                session.add(asset_alias_model)\n\n                dags_to_queue_from_asset_alias |= {\n                    alias_ref.dag\n                    for alias_ref in asset_alias_model.scheduled_dags\n                    if not alias_ref.dag.is_paused\n                }\n        else:\n            asset_alias_models = []\n\n        dags_to_queue_from_asset_ref = set(\n            session.scalars(\n                select(DagModel)\n                .join(DagModel.schedule_asset_name_references, isouter=True)\n                .join(DagModel.schedule_asset_uri_references, isouter=True)\n                .where(\n                    or_(\n                        DagScheduleAssetNameReference.name == asset.name,\n                        DagScheduleAssetUriReference.uri == asset.uri,\n                    ),\n                    DagModel.is_paused.is_(False),\n                )\n            )\n        )\n\n        asset = asset_model.to_serialized()\n        cls.notify_asset_changed(asset=asset)\n        cls.nofity_asset_event_emitted(\n            asset_event=ListenerAssetEvent(\n                asset=asset,\n                extra=asset_event.extra,\n                source_dag_id=asset_event.source_dag_id,\n                source_task_id=asset_event.source_task_id,\n                source_run_id=asset_event.source_run_id,\n                source_map_index=asset_event.source_map_index,\n                source_aliases=[aam.to_serialized() for aam in asset_alias_models],\n                partition_key=partition_key,\n            )\n        )\n\n        Stats.incr("asset.updates")\n\n        dags_to_queue = (\n            dags_to_queue_from_asset | dags_to_queue_from_asset_alias | dags_to_queue_from_asset_ref\n        )\n        log.debug("asset event added", asset_event=asset_event, dags_to_queue=dags_to_queue)\n        cls._queue_dagruns(\n            asset_id=asset_model.id,\n            dags_to_queue=dags_to_queue,\n            partition_key=partition_key,\n            event=asset_event,\n            task_instance=task_instance,\n            session=session,\n        )\n        return asset_event\n\n    @staticmethod\n    def notify_asset_created(asset: SerializedAsset):\n        """Run applicable notification actions when an asset is created."""\n        try:\n            get_listener_manager().hook.on_asset_created(asset=asset)\n        except Exception:\n            log.exception("error calling listener")\n\n    @staticmethod\n    def notify_asset_alias_created(asset_assets: SerializedAssetAlias):\n        """Run applicable notification actions when an asset alias is created."""\n        try:\n            get_listener_manager().hook.on_asset_alias_created(asset_alias=asset_assets)\n        except Exception:\n            log.exception("error calling listener")\n\n    @staticmethod\n    def notify_asset_changed(asset: SerializedAsset) -> None:\n        """Run applicable notification actions when an asset is changed."""\n        try:\n            get_listener_manager().hook.on_asset_changed(asset=asset)\n        except Exception:\n            log.exception("error calling listener")\n\n    @staticmethod\n    def nofity_asset_event_emitted(asset_event: ListenerAssetEvent) -> None:\n        """Run applicable notification actions when an asset event is emitted."""\n        try:\n            get_listener_manager().hook.on_asset_event_emitted(asset_event=asset_event)\n        except Exception:\n            log.exception("error calling listener")\n\n    @classmethod\n    def _queue_dagruns(\n        cls,\n        *,\n        asset_id: int,\n        dags_to_queue: set[DagModel],\n        partition_key: str | None,\n        event: AssetEvent,\n        task_instance: TaskInstance | None,\n        session: Session,\n    ) -> None:\n        log.debug("Dags to queue", dags_to_queue=dags_to_queue)\n        if not dags_to_queue:\n            return None\n\n        partition_dags = [x for x in dags_to_queue if x.timetable_partitioned is True]\n        cls._queue_partitioned_dags(\n            asset_id=asset_id,\n            partition_dags=partition_dags,\n            event=event,\n            partition_key=partition_key,\n            task_instance=task_instance,\n            session=session,\n        )\n\n        non_partitioned_dags = dags_to_queue.difference(partition_dags)  # don\'t double process\n        if not non_partitioned_dags:\n            return None\n\n        # Possible race condition: if multiple dags or multiple (usually\n        # mapped) tasks update the same asset, this can fail with a unique\n        # constraint violation.\n        #\n        # If we support it, use ON CONFLICT to do nothing, otherwise\n        # "fallback" to running this in a nested transaction. This is needed\n        # so that the adding of these rows happens in the same transaction\n        # where `ti.state` is changed.\n        if get_dialect_name(session) == "postgresql":\n            return cls._queue_dagruns_nonpartitioned_postgres(asset_id, non_partitioned_dags, session)\n        return cls._queue_dagruns_nonpartitioned_slow_path(asset_id, non_partitioned_dags, session)\n\n    @classmethod\n    def _queue_partitioned_dags(\n        cls,\n        *,\n        asset_id: int,\n        partition_dags: Iterable[DagModel],\n        event: AssetEvent,\n        partition_key: str | None,\n        task_instance: TaskInstance | None,\n        session: Session,\n    ) -> None:\n        if partition_dags and not partition_key:\n            prefix = "Listening Dags are partition-aware but the run has no partition key"\n            log.warning(\n                prefix,\n                listening_dags=[x.dag_id for x in partition_dags],\n                asset_id=asset_id,\n                run_id=event.source_run_id,\n                dag_id=event.source_dag_id,\n                task_id=event.source_task_id,\n            )\n            msg = (\n                f"{prefix} (listening_dags={[x.dag_id for x in partition_dags]}, "\n                f"asset_id={asset_id}, "\n                f"run_id={event.source_run_id}, "\n                f"dag_id={event.source_dag_id}, "\n                f"task_id={event.source_task_id})"\n            )\n            session.add(\n                Log(\n                    event="missing partition key",\n                    extra=msg,\n                    task_instance=task_instance,\n                )\n            )\n            return\n\n        for target_dag in partition_dags:\n            if TYPE_CHECKING:\n                assert partition_key is not None\n            from airflow.models.serialized_dag import SerializedDagModel\n\n            if not (serdag := SerializedDagModel.get(dag_id=target_dag.dag_id, session=session)):\n                raise RuntimeError(f"Could not find serialized dag for dag_id={target_dag.dag_id}")\n\n            timetable = serdag.dag.timetable\n            if TYPE_CHECKING:\n                assert isinstance(timetable, PartitionedAssetTimetable)\n\n            if (asset_model := session.scalar(select(AssetModel).where(AssetModel.id == asset_id))) is None:\n                raise RuntimeError(f"Could not find asset for asset_id={asset_id}")\n\n            try:\n                # We\'ll need to catch every possible exception happen when mapping partition_key.\n                target_key = timetable.get_partition_mapper(\n                    name=asset_model.name, uri=asset_model.uri\n                ).to_downstream(partition_key)\n            except Exception as err:\n                log.exception(\n                    "Could not map partition key for asset in target Dag. "\n                    "This likely indicates the target Dag\'s partition mapper "\n                    "is misconfigured, or does not support this partition key.",\n                    partition_key=partition_key,\n                    asset=asset_model,\n                    target_dag=target_dag,\n                )\n                log_extra = (\n                    f"Could not map partition_key \'{partition_key}\' for asset "\n                    f"(name=\'{asset_model.name}\', uri=\'{asset_model.uri}\') in target Dag "\n                    f"\'{target_dag.dag_id}\'. This likely indicates that the partition "\n                    f"mapper in the target Dag is misconfigured or does not support this "\n                    f"partition key.\\n{type(err).__name__}: {err}"\n                )\n                session.add(\n                    Log(\n                        event="failed to map partition_key",\n                        extra=log_extra,\n                        task_instance=task_instance,\n                    )\n                )\n                continue\n\n            if is_container(target_key):\n                # TODO (AIP-76): This never happens now. When we implement\n                # one-to-many partition key mapping, this should also add a\n                # config to cap the iterable size so the scheduler does not\n                # blow up with an incorrectly implemented PartitionMapper.\n                target_keys: Iterable[str] = target_key\n            else:\n                target_keys = [target_key]\n            del target_key\n\n            for target_key in target_keys:\n                apdr = cls._get_or_create_apdr(\n                    target_key=target_key,\n                    target_dag=target_dag,\n                    asset_id=asset_id,\n                    session=session,\n                )\n                log_record = PartitionedAssetKeyLog(\n                    asset_id=asset_id,\n                    asset_event_id=event.id,\n                    asset_partition_dag_run_id=apdr.id,\n                    source_partition_key=partition_key,\n                    target_dag_id=target_dag.dag_id,\n                    target_partition_key=target_key,\n                )\n                session.add(log_record)\n\n    @classmethod\n    def _get_or_create_apdr(\n        cls,\n        *,\n        target_key: str,\n        target_dag: SerializedDagModel,\n        asset_id: int,\n        session: Session,\n    ) -> AssetPartitionDagRun:\n        """\n        Get or create an APDR.\n\n        If 2 processes invoke this method at the same time using the same (target_key, target_dag) pair,\n        they may both check the database and, finding no existing APDR, create separate instances.\n        This leads to the unintended outcome of having two APDRs created instead of one.\n        To resolve this, we add a mutex lock to AssetModel for PostgreSQL and MySQL and use\n        AssetPartitionDagRunMutexLock table for SQLite.\n        """\n        with _lock_asset_model(session=session, asset_id=asset_id):\n            latest_apdr: AssetPartitionDagRun | None = session.scalar(\n                select(AssetPartitionDagRun)\n                .where(\n                    AssetPartitionDagRun.partition_key == target_key,\n                    AssetPartitionDagRun.target_dag_id == target_dag.dag_id,\n                )\n                .order_by(AssetPartitionDagRun.id.desc())\n                .limit(1)\n            )\n            if latest_apdr and latest_apdr.created_dag_run_id is None:\n                cls.logger().debug(\n                    "Existing APDR found for key %s dag_id %s",\n                    target_key,\n                    target_dag.dag_id,\n                    exc_info=True,\n                )\n                return latest_apdr\n\n            apdr = AssetPartitionDagRun(\n                target_dag_id=target_dag.dag_id,\n                created_dag_run_id=None,\n                partition_key=target_key,\n            )\n            session.add(apdr)\n            session.flush()\n            cls.logger().debug(\n                "No existing APDR found. Create APDR for key %s dag_id %s",\n                target_key,\n                target_dag.dag_id,\n                exc_info=True,\n            )\n            return apdr\n\n    @classmethod\n    def _queue_dagruns_nonpartitioned_slow_path(\n        cls, asset_id: int, dags_to_queue: set[DagModel], session: Session\n    ) -> None:\n        def _queue_dagrun_if_needed(dag: DagModel) -> str | None:\n            item = AssetDagRunQueue(target_dag_id=dag.dag_id, asset_id=asset_id)\n            # Don\'t error whole transaction when a single RunQueue item conflicts.\n            # https://docs.sqlalchemy.org/en/14/orm/session_transaction.html#using-savepoint\n            try:\n                with session.begin_nested():\n                    session.merge(item)\n            except exc.IntegrityError:\n                cls.logger().debug("Skipping record %s", item, exc_info=True)\n            return dag.dag_id\n\n        queued_results = (_queue_dagrun_if_needed(dag) for dag in dags_to_queue)\n        if queued_dag_ids := [r for r in queued_results if r is not None]:\n            cls.logger().debug("consuming dag ids %s", queued_dag_ids)\n\n    @classmethod\n    def _queue_dagruns_nonpartitioned_postgres(\n        cls, asset_id: int, dags_to_queue: set[DagModel], session: Session\n    ) -> None:\n        from sqlalchemy.dialects.postgresql import insert\n\n        values = [{"target_dag_id": dag.dag_id} for dag in dags_to_queue]\n        stmt = insert(AssetDagRunQueue).values(asset_id=asset_id).on_conflict_do_nothing()\n        session.execute(stmt, values)\n\n\ndef resolve_asset_manager() -> AssetManager:\n    """Retrieve the asset manager."""\n    _asset_manager_class = conf.getimport(\n        section="core",\n        key="asset_manager_class",\n        fallback="airflow.assets.manager.AssetManager",\n    )\n    _asset_manager_kwargs = conf.getjson(\n        section="core",\n        key="asset_manager_kwargs",\n        fallback={},\n    )\n    return _asset_manager_class(**_asset_manager_kwargs)\n\n\nasset_manager = resolve_asset_manager()\n',
            'airflow-core/tests/unit/assets/test_manager.py': '#\n# Licensed to the Apache Software Foundation (ASF) under one\n# or more contributor license agreements.  See the NOTICE file\n# distributed with this work for additional information\n# regarding copyright ownership.  The ASF licenses this file\n# to you under the Apache License, Version 2.0 (the\n# "License"); you may not use this file except in compliance\n# with the License.  You may obtain a copy of the License at\n#\n#   http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing,\n# software distributed under the License is distributed on an\n# "AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\n# KIND, either express or implied.  See the License for the\n# specific language governing permissions and limitations\n# under the License.\nfrom __future__ import annotations\n\nimport concurrent.futures\nimport itertools\nimport logging\nfrom collections import Counter\nfrom typing import TYPE_CHECKING\nfrom unittest import mock\n\nimport pytest\nfrom sqlalchemy import delete, func, select\nfrom sqlalchemy.orm import Session\n\nfrom airflow import settings\nfrom airflow.assets.manager import AssetManager\nfrom airflow.models.asset import (\n    AssetAliasModel,\n    AssetDagRunQueue,\n    AssetEvent,\n    AssetModel,\n    AssetPartitionDagRun,\n    DagScheduleAssetAliasReference,\n    DagScheduleAssetReference,\n)\nfrom airflow.models.dag import DAG, DagModel\nfrom airflow.sdk.definitions.asset import Asset\n\nfrom unit.listeners import asset_listener\n\npytestmark = pytest.mark.db_test\n\n\npytest.importorskip("pydantic", minversion="2.0.0")\n\n\n@pytest.fixture\ndef clear_assets():\n    from tests_common.test_utils.db import clear_db_assets\n\n    clear_db_assets()\n    yield\n    clear_db_assets()\n\n\n@pytest.fixture\ndef mock_task_instance():\n    # TODO: Fixme - some mock_task_instance is needed here\n    return None\n\n\ndef create_mock_dag():\n    for dag_id in itertools.count(1):\n        mock_dag = mock.Mock(spec=DAG)\n        mock_dag.dag_id = dag_id\n        yield mock_dag\n\n\nclass TestAssetManager:\n    def test_register_asset_change_asset_doesnt_exist(self, mock_task_instance):\n        mock_task_instance = mock.Mock()\n        asset = Asset(uri="asset_doesnt_exist", name="not exist")\n\n        mock_session = mock.Mock(spec=Session)\n        # Gotta mock up the query results\n        mock_session.scalar.return_value = None\n\n        asset_manger = AssetManager()\n        asset_manger.register_asset_change(\n            task_instance=mock_task_instance, asset=asset, session=mock_session\n        )\n\n        # Ensure that we have ignored the asset and _not_ created an AssetEvent or\n        # AssetDagRunQueue rows\n        mock_session.add.assert_not_called()\n        mock_session.merge.assert_not_called()\n\n    @pytest.mark.usefixtures("dag_maker", "testing_dag_bundle")\n    def test_register_asset_change(self, session, mock_task_instance):\n        asset_manager = AssetManager()\n\n        asset = Asset(uri="test://asset1", name="test_asset_uri", group="asset")\n        bundle_name = "testing"\n\n        dag1 = DagModel(dag_id="dag1", is_stale=False, bundle_name=bundle_name)\n        dag2 = DagModel(dag_id="dag2", is_stale=False, bundle_name=bundle_name)\n        session.add_all([dag1, dag2])\n\n        asm = AssetModel(uri="test://asset1/", name="test_asset_uri", group="asset")\n        session.add(asm)\n        asm.scheduled_dags = [DagScheduleAssetReference(dag_id=dag.dag_id) for dag in (dag1, dag2)]\n        session.execute(delete(AssetDagRunQueue))\n        session.flush()\n\n        asset_manager.register_asset_change(task_instance=mock_task_instance, asset=asset, session=session)\n        session.flush()\n\n        # Ensure we\'ve created an asset\n        assert (\n            session.scalar(select(func.count()).select_from(AssetEvent).where(AssetEvent.asset_id == asm.id))\n            == 1\n        )\n        assert session.scalar(select(func.count()).select_from(AssetDagRunQueue)) == 2\n\n    @pytest.mark.usefixtures("clear_assets")\n    def test_register_asset_change_with_alias(\n        self, session, dag_maker, mock_task_instance, testing_dag_bundle\n    ):\n        bundle_name = "testing"\n\n        consumer_dag_1 = DagModel(\n            dag_id="conumser_1", bundle_name=bundle_name, is_stale=False, fileloc="dag1.py"\n        )\n        consumer_dag_2 = DagModel(\n            dag_id="conumser_2", bundle_name=bundle_name, is_stale=False, fileloc="dag2.py"\n        )\n        session.add_all([consumer_dag_1, consumer_dag_2])\n\n        asm = AssetModel(uri="test://asset1/", name="test_asset_uri", group="asset")\n        session.add(asm)\n\n        asam = AssetAliasModel(name="test_alias_name", group="test")\n        session.add(asam)\n        asam.scheduled_dags = [\n            DagScheduleAssetAliasReference(alias_id=asam.id, dag_id=dag.dag_id)\n            for dag in (consumer_dag_1, consumer_dag_2)\n        ]\n        session.execute(delete(AssetDagRunQueue))\n        session.flush()\n\n        asset = Asset(uri="test://asset1", name="test_asset_uri")\n        asset_manager = AssetManager()\n        asset_manager.register_asset_change(\n            task_instance=mock_task_instance,\n            asset=asset,\n            source_alias_names=["test_alias_name"],\n            session=session,\n        )\n        session.flush()\n\n        # Ensure we\'ve created an asset\n        assert (\n            session.scalar(select(func.count()).select_from(AssetEvent).where(AssetEvent.asset_id == asm.id))\n            == 1\n        )\n        assert session.scalar(select(func.count()).select_from(AssetDagRunQueue)) == 2\n\n    def test_register_asset_change_no_downstreams(self, session, mock_task_instance):\n        asset_manager = AssetManager()\n\n        asset = Asset(uri="test://asset1", name="never_consumed")\n        asm = AssetModel(uri="test://asset1/", name="never_consumed", group="asset")\n        session.add(asm)\n        session.execute(delete(AssetDagRunQueue))\n        session.flush()\n\n        asset_manager.register_asset_change(task_instance=mock_task_instance, asset=asset, session=session)\n        session.flush()\n\n        # Ensure we\'ve created an asset\n        assert (\n            session.scalar(select(func.count()).select_from(AssetEvent).where(AssetEvent.asset_id == asm.id))\n            == 1\n        )\n        assert session.scalar(select(func.count()).select_from(AssetDagRunQueue)) == 0\n\n    def test_register_asset_change_notifies_asset_listener(\n        self, session, mock_task_instance, testing_dag_bundle, listener_manager\n    ):\n        asset_manager = AssetManager()\n        asset_listener.clear()\n        listener_manager(asset_listener)\n\n        bundle_name = "testing"\n\n        asset = Asset(uri="test://asset1", name="test_asset_1")\n        dag1 = DagModel(dag_id="dag3", bundle_name=bundle_name)\n        session.add(dag1)\n\n        asm = AssetModel(uri="test://asset1/", name="test_asset_1", group="asset")\n        session.add(asm)\n        asm.scheduled_dags = [DagScheduleAssetReference(dag_id=dag1.dag_id)]\n        session.flush()\n\n        asset_manager.register_asset_change(task_instance=mock_task_instance, asset=asset, session=session)\n        session.flush()\n\n        # Ensure the listener was notified\n        assert len(asset_listener.changed) == 1\n        assert asset_listener.changed[0].uri == asset.uri\n\n    def test_create_assets_notifies_asset_listener(self, session, listener_manager):\n        asset_manager = AssetManager()\n        asset_listener.clear()\n        listener_manager(asset_listener)\n\n        asset = Asset(uri="test://asset1", name="test_asset_1")\n\n        asms = asset_manager.create_assets([asset], session=session)\n\n        # Ensure the listener was notified\n        assert len(asset_listener.created) == 1\n        assert len(asms) == 1\n        assert asset_listener.created[0].uri == asset.uri == asms[0].uri\n\n    @pytest.mark.usefixtures("dag_maker", "testing_dag_bundle")\n    def test_get_or_create_apdr_race_condition(self, session, caplog):\n        asm = AssetModel(uri="test://asset1/", name="partition_asset", group="asset")\n        testing_dag = DagModel(dag_id="testing_dag", is_stale=False, bundle_name="testing")\n        session.add_all([asm, testing_dag])\n        session.commit()\n        session.flush()\n        assert session.scalar(select(func.count()).select_from(AssetPartitionDagRun)) == 0\n\n        def _get_or_create_apdr():\n            if TYPE_CHECKING:\n                assert settings.Session\n                assert settings.Session.session_factory\n\n            _session = settings.Session.session_factory()\n            _session.begin()\n            try:\n                return AssetManager._get_or_create_apdr(\n                    target_key="test_partition_key",\n                    target_dag=testing_dag,\n                    asset_id=asm.id,\n                    session=_session,\n                ).id\n            finally:\n                _session.commit()\n                _session.close()\n\n        thread_count = 100\n        with caplog.at_level(logging.DEBUG):\n            with concurrent.futures.ThreadPoolExecutor(max_workers=thread_count) as pool:\n                ids = pool.map(lambda _: _get_or_create_apdr(), [None] * thread_count)\n\n        assert Counter(r.msg for r in caplog.records) == {\n            "Existing APDR found for key test_partition_key dag_id testing_dag": thread_count - 1,\n            "No existing APDR found. Create APDR for key test_partition_key dag_id testing_dag": 1,\n        }\n\n        assert len(set(ids)) == 1\n        assert session.scalar(select(func.count()).select_from(AssetPartitionDagRun)) == 1\n\n    @pytest.mark.usefixtures("testing_dag_bundle")\n    def test_register_asset_change_queues_stale_dag(self, session, mock_task_instance):\n        asset_manager = AssetManager()\n        bundle_name = "testing"\n\n        # Setup an Asset\n        asset_uri = "test://stale_asset/"\n        asset_name = "test_stale_asset"\n        asset_definition = Asset(uri=asset_uri, name=asset_name)\n\n        asm = AssetModel(uri=asset_uri, name=asset_name, group="asset")\n        session.add(asm)\n\n        # Setup a Dag that is STALE but NOT PAUSED\n        # We want stale Dags to still receive asset updates\n        stale_dag = DagModel(dag_id="stale_dag", is_stale=True, is_paused=False, bundle_name=bundle_name)\n        session.add(stale_dag)\n\n        # Link the Stale Dag to the Asset\n        asm.scheduled_dags = [DagScheduleAssetReference(dag_id=stale_dag.dag_id)]\n\n        session.execute(delete(AssetDagRunQueue))\n        session.flush()\n\n        # Register the asset change\n        asset_manager.register_asset_change(\n            task_instance=mock_task_instance, asset=asset_definition, session=session\n        )\n        session.flush()\n\n        # Verify the stale Dag was NOT ignored\n        assert session.scalar(select(func.count()).select_from(AssetDagRunQueue)) == 1\n\n        queued_id = session.scalar(select(AssetDagRunQueue.target_dag_id))\n        assert queued_id == "stale_dag"\n',
        }
